var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"수수께끼가 모두 풀렸다고?","JPN":"謎が解けた？","ENG":"The mystery has been solved?","TWN":"謎底都解開了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"범인을 찾았다는 뜻이야?","JPN":"犯人を見つけたってこと？","ENG":"Do you know who the perpetrator is?","TWN":"妳是說找到兇手了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"맞아요. 그리고 범인은 바로 이 장소에 있습니다.","JPN":"はい、そして犯人はここにいます。","ENG":"Yes, and she's right here and now.","TWN":"是的，那個兇手就在這裡。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"방금 그 얘기로 범인을 알아차렸다고? 어떻게?","JPN":"今の話でわかったって言うわけ？　どうやって？","ENG":"You found the perpetrator after those two questions. How?","TWN":"就通過剛剛那幾個問題找到了兇手？怎麼可能？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"처음으로 이상하다고 생각했던 건 선배의 불완전한 알리바이였어요.","JPN":"最初、おかしいと思ったのは先輩の不完全なアリバイでした。","ENG":"The first strange thing I noticed was Shiyoon's incomplete alibi.","TWN":"剛開始我覺得很奇怪的是前輩有個並不完美的不在場證明。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"애초에 그 선배가 이런 귀찮은 일을 저지를 성격도 아니지만......","JPN":"それに、先輩がこんな面倒なことをする性格でもありませんし……","ENG":"First of all, he's not the type who would bother to go through all this trouble,","TWN":"而且依前輩的性格，他並不是會做這種麻煩事的人……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"만약 정말 성야의 살인마였다면 왜 그렇게 어설프게 움직였을까요?","JPN":"もし、本当に聖夜の殺人鬼だったなら、なぜあんな怪しい行動を取ったのか。","ENG":"and even if he was, he wouldn't have done it so sloppily like this.","TWN":"如果他真的是耶誕的嫌疑犯，那他為什麼會那麼粗心？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"어설퍼? 어떤 부분이?","JPN":"怪しい？　どこがですか？","ENG":"So sloppily? In which part?","TWN":"粗心？妳的意思是？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배는 그 촌스러운 출근복을 스무 벌이나 사다 놓고 매일 갈아입는 사람이에요.","JPN":"先輩はあのダサい服を二十着も用意して、毎日着替える人です。","ENG":"Shiyoon is so fastidious that he bought twenty sets of tacky-looking clothes, of the same design, so he could wear a fresh one every day.","TWN":"前輩是一個買二十套一模一樣的工作服，然後每天換洗的人。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런 사람이 어째서 지우는 데 몇 분 걸리지도 않을 커피 자국을 남겨 두는 바람에 의심 받게 됐을까요?","JPN":"そんな人が、どうして落とすのに数分もかからない\\nコーヒーの染みを残したまま、私が疑うように仕向けたのでしょうか？","ENG":"If he really was the mastermind, he would never have left the coffee stains on him, which he could have gotten rid of in a few minutes.","TWN":"那樣的人為什麼身上會留著幾分鐘就可以擦掉的咖啡漬，然後讓人懷疑呢？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그것뿐만이 아니에요.","JPN":"それだけではありません。","ENG":"That's not all.","TWN":"不僅如此。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배가 작정하고 기습했다면 우리 둘을 쓰러뜨리긴 어렵지 않았을 거예요.","JPN":"先輩が本気で奇襲したのであれば、私たち二人を倒すのはそう難しくなかったはずです。","ENG":"If Shiyoon really wanted to defeat us, he could have done it easily.","TWN":"如果前輩真要襲擊，那麼他可以輕而易舉打敗我們。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 선배는 매번 적당히 상대하다가 도망쳐 버렸죠.","JPN":"でも先輩は、毎回適当に私たちの相手をしては逃げてしまいました。","ENG":"But he always ran away after a while,","TWN":"可前輩每次都是適當的出手之後便逃走了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"꼭 우리를 쓰러뜨리면 안 되는 것처럼요.","JPN":"私たちを倒してはいけないかのように。","ENG":"as if he had reasons not to take us down.","TWN":"就好像是刻意的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"우릴 쓰러뜨리면 안 된다고? 그럴 이유가 있어?","JPN":"アタシたちを倒してはいけない？　なんで？","ENG":"Reasons not to take us down?","TWN":"刻意？為什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"중요한 이유가 있죠.","JPN":"重要な理由があります。","ENG":"There was an important reason.","TWN":"有一個很重要的理由。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"만약 선배에게 쓰러뜨려진 우리가 성야의 희생자로 변하지 않으면......","JPN":"もし先輩に倒された私たちが、聖夜の犠牲者にならなければ……","ENG":"If he beat us and we didn't turn into the victims of the Holy Night,","TWN":"如果前輩打敗我們之後，我們沒有成為耶誕的受害者……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"희생자가 새로운 희생자를 만들 수 있다는 설정은 사용할 수 없으니까요!","JPN":"犠牲者が新しい犠牲者を作るという設定が使えなくなるからです！","ENG":"then the perpetrator couldn't use the device to turn others.","TWN":"那麼就無法坐實受害者可以造成新的受害者這一事實！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT"},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐? 그 얘기는 하는 짓만 좀비 같단 뜻이야?","JPN":"えっ？　つまり、ゾンビに見えてるだけでゾンビじゃないってこと？","ENG":"What? Are you saying they're zombies, but not contagious?","TWN":"什麼？妳的意思是，只有看起來像僵屍是嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"맞아요. 희생자를 늘릴 수 있는 사람은 성야의 살인마 본인 뿐이에요.","JPN":"そうです。犠牲者を増やせるのは聖夜の殺人鬼本人だけです。","ENG":"Yes. Only the Killer of the Holy Night herself can multiply her victims.","TWN":"是的，能讓人變成受害者的其實只有耶誕的嫌疑犯本人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그리고 우리에게 잘못된 정보를 전달하려고 한 사람.","JPN":"そして、私たちに間違った情報を伝えようとした一人。","ENG":"And someone has been feeding us the wrong information.","TWN":"還有，故意把錯誤的情報告訴我們的人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"알렉스! 당신이 바로 성야의 살인마입니다!","JPN":"アレックス！　あなたが聖夜の殺人鬼です！","ENG":"That person is you, Alex. You're the Killer of the Holy Night!","TWN":"雅蕾克絲！妳就是耶誕的嫌疑犯！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음...... 갑자기 의심 받으니 조금 당황스럽네.","JPN":"ふーん……急に犯人扱いだなんて心外ね。","ENG":"Hm... This is so sudden that I don't know what to say.","TWN":"唔……這突如其來的懷疑，讓我很驚慌啊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"나는 내가 본 걸 사실대로 말했을 뿐이야.","JPN":"私は見たままのことを話しただけよ。","ENG":"I only told you what I saw.","TWN":"我只是說出了我看到的事實而已。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그리고 애초에 이 중에서 알리바이가 있는 사람은 나 혼자 아니려나?","JPN":"それに、この中で唯一アリバイがあるのは私だけじゃない。","ENG":"Also, of the three of us, I'm the only one with an alibi.","TWN":"而且我們之中，只有我有不在場證明吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"알리바이도 확실하지 않은 사람에게 범인으로 몰리다니 난처하네.","JPN":"アリバイも確かじゃない人たちに、犯人扱いされるなんて困るわ。","ENG":"I don't know how I feel about being called the perpetrator by someone whose alibi isn't clear.","TWN":"被一個連不在場證明都沒有的人視為兇手，真是為難啊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"으음......","JPN":"う～ん……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그렇게 말할 줄 알았어요.","JPN":"そう言うと思いました。","ENG":"I knew you'd say that.","TWN":"我就知道妳會那麼說。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 당신의 알리바이도 그렇게 견고하진 않아요.","JPN":"でもあなたのアリバイも確かじゃありません。","ENG":"But your alibi isn't solid, either.","TWN":"但妳的不在場證明也並不是完美的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"애초에 그 알리바이를 증언해 준 사람은 소림 양이잖아요?","JPN":"そもそも、そのアリバイを証言してくれたのはミズキさんですよね？","ENG":"Your alibi is Sorim, right?","TWN":"能證實妳不在場證明的人只有韓蕭林小姐吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"맞아. 그 아이가 왜?","JPN":"そうよ。あの子がどうかしたの？","ENG":"Yes. So?","TWN":"是的，怎麼了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"기억을 되돌려 봐요. 소림 양이 그때 뭐라고 했죠?","JPN":"思い出してみてください。あの時ミズキさんが何と言ったか。","ENG":"Why don't you try to recall the conversation? What did Sorim say?","TWN":"妳想想，但是韓蕭林小姐是怎麼說的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"참고로 알렉스 대원의 품은 따뜻하고 폭신폭신해서 잠들기에 딱 좋았다.","JPN":"参考までに、アレックス隊員の胸の中は温かくて柔らかくて、眠るのにピッタリの場所だ。","ENG":"I'll have you know her bosom was so warm and plush that I fell asleep almost instantly.","TWN":"雅蕾克絲隊員的懷抱非常暖和且柔軟， 正適合睡覺。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"이런 폭신폭신함은 엄마품 이후로 처음이었지.","JPN":"こんな柔らかな感覚は、母の胸以外では初めてだった。","ENG":"I've never felt so comfortable in anyone's arms since my mom's.","TWN":"這種柔軟，除了媽媽以外還是第一次。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......그렇네. 그 허약해 보이는 꼬맹이, 분명 잠들었다고 했어.","JPN":"……確かに。あの子は眠ってたって言ってた。","ENG":"You're right. That feeble-looking girl said she fell asleep.","TWN":"……對啊，那個看起來虛弱的小傢伙，分明說自己睡著了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"소림 양을 재우고 나서 자리를 비웠다 돌아왔다면 그 애가 알 리 없겠죠.","JPN":"ミズキさんを寝かしつけてから、その場を離れて戻ったとしても気づくわけがありません。","ENG":"Sorim wouldn't have known even if you left her after she fell asleep.","TWN":"韓蕭林小姐睡著以後，哪怕妳出去了之後再回來她也是不知道的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"인정할게. 하지만 그것 하나만으로 범인이라기엔 억지 아닐까?","JPN":"認めるわ。でもそれだけで犯人だっていうのは無理があるんじゃない？","ENG":"True, but that alone is not good enough proof, don't you think?","TWN":"我不否認，但是僅憑這一點就說我是兇手，未免也太牽強了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"의심스러운 정황은 그것만이 아니에요.","JPN":"怪しいのは、それだけじゃありません。","ENG":"There's more.","TWN":"可疑點不止那一個。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배는 우리와 싸우다 퇴각하고 곧바로 소림 양을 공격해서 희생자로 만들었죠.","JPN":"先輩は私たちとの戦いを止め、すぐにミズキさんを攻撃して犠牲者にしました。","ENG":"Shiyoon left us in the middle of a fight to attack and victimize Sorim.","TWN":"前輩在和我們打完架撤退的時候，攻擊了韓蕭林小姐，讓她成為了受害者。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"처음에는 단순히 혼자 떨어져 있는 일행을 공격한 줄 알았지만 사실은 아니었어요.","JPN":"最初は私たちと離れている人たちを攻撃したんだとばかり思ってましたが、実際は違いました。","ENG":"At first, I thought he attacked her because she was alone. I was wrong though.","TWN":"剛開始我以為只是攻擊了落單的人，但其實並不是。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제가 선배의 알리바이를 무너뜨린 걸 보고 만약에 대비해 입을 막은 거죠.","JPN":"私が先輩のアリバイを崩したのを見て、もしもの時のために口封じをしたのです。","ENG":"After I saw through Shiyoon's flimsy alibi, you decided to shut her up, just in case.","TWN":"妳看到我反駁前輩的不在場證明後，以防萬一，用這種方式堵住了她的嘴。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 그 녀석이 꼬맹이를 희생자로 만들었다는 거야? 희생자는 희생자를 못 늘린다며?","JPN":"それじゃあ、あいつがあの子を犠牲者にしたってこと？\\n犠牲者は他の人を犠牲者にできないんじゃなかった？","ENG":"Are you saying he turned that girl into a victim? But you said victims can't turn others.","TWN":"所以說是那個人讓小傢伙變成了受害者？妳不是說受害者不能造成受害者嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"맞아요. 하지만 소림 양은 그때 혼자가 아니었잖아요.","JPN":"そうです。でもミズキさんはその時一人ではありませんでした。","ENG":"They can't. But Sorim wasn't alone at that time.","TWN":"是的，不過韓蕭林小姐那時候並不是自己一個人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아하...... 그러네. 한 명 더 있었지.","JPN":"あぁ……確かに、もう一人いたっけ。","ENG":"Ah... You're right. She was with someone else.","TWN":"啊哈……是啊，還有一個人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그래요. 소림 양을 희생자로 만든 사람은 선배가 아니라 범인인 알렉스 씨였어요.","JPN":"そうです。ミズキさんを犠牲者にした人は先輩ではなく犯人であるアレックスさんです。","ENG":"Yes. It wasn't Shiyoon who turned Sorim but it was you, Alex. You did it.","TWN":"是的，把韓蕭林小姐變成受害者的兇手並不是前輩，而是雅蕾克絲。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"파티장에서도 마찬가지예요. 당신과 얘기한 뒤에 선배가 잠시 사라졌죠.","JPN":"パーティー会場でも同じです。あなたと話した後に先輩が消えました。","ENG":"Even when we were at the party, Shiyoon disappeared for a while after talking to you.","TWN":"在宴會廳也是，跟妳聊完之後前輩就不見了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨, 카일 씨는 어땠어요?","JPN":"シルビアさん、カイルさんはどうでしたか？","ENG":"Sylvia, what did Kyle do when he was there?","TWN":"希爾維亞，那麼凱爾呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"파티 관계자들을 만나 본다고 했어. 가능성은 충분해.","JPN":"パーティー関係者に会いに行くと言ってたわ。可能性は十分ある。","ENG":"He went to see the party staff. It's possible the same thing happened to him.","TWN":"他說去見見派對的負責人，有充分的可能性。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"오호라......","JPN":"あら……","ENG":"Oh...","TWN":"啊哈……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......제가 마지막으로 당신이 범인이라고 확신한 건 당신에게 했던 질문이에요.","JPN":"……私が最後にあなたが犯人だと確信を持てたのは、あなたへの質問です。","ENG":"Lastly, I was convinced that you were the perpetrator after you answered my question.","TWN":"……最後我斷定妳就是兇手，是因為我問妳的幾個問題。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"질문이라, 뭘 물어 봤더라?","JPN":"質問？　どんな質問だったかしら？","ENG":"Okay, what was your question?","TWN":"問題，什麼問題？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"당신은 제이크 대령이 몰래 메이드 아가씨들을 뒤에서 기습했다고 했어요.","JPN":"あなたはジェイク大佐がメイドのお嬢さんたちを、後ろから奇襲したと言いました。","ENG":"You said Colonel Jake attacked the maid ladies from behind.","TWN":"妳說是傑克上校偷偷在背後襲擊了女僕。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"맞아. 그랬지.","JPN":"ええ、そうよ。","ENG":"Yes, I did.","TWN":"噢，是的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"전 그 리플레이서 사태 때 그 사람과 같이 싸워본 적이 있어요.","JPN":"私はリプレイサー事件の時に、あの人と戦ったことがあります。","ENG":"I fought alongside him during the Replacer incident.","TWN":"我在克隆集團事件時，和他一起作戰過。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제이크 대령은 몰래 뒤로 돌아가서 기습할 만한 사람이 아니죠.","JPN":"ジェイク大佐は隠れて後ろから奇襲するような人ではありませんでした。","ENG":"Colonel Jake would never attack someone from behind.","TWN":"傑克上校並不是一個會從背後偷襲的人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"애초에 번개가 번쩍이는 주먹을 휘두르는 사람이 무슨 수로 몰래 숨어들겠어요?","JPN":"そもそも雷の拳を振り回す人がどんな手を使えば、こっそり後ろから攻撃できると言うんですか？","ENG":"He can't, even if he wants to. He's got lightning-charged fists for God.","TWN":"他那個拳頭就跟閃電一樣，怎麼能偷偷躲在後面？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"맞아! 그 멍청이는 정면 대결 말고는 싸우는 법을 모르는 녀석이라고.","JPN":"確かに！　あのバカは正面対決以外はできないやつよ！","ENG":"That's right. That fool only fights head-to-head.","TWN":"沒錯！那個蠢貨除了正面對決，都不知道怎麼用其他辦法打。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"뭐, 재미있는 추리였어.","JPN":"まぁ、面白い推理だったわ。","ENG":"Well, that's an interesting way of deducing things.","TWN":"真是個有趣的推理。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 박수를 쳐주기엔 너무 엉성한 걸?","JPN":"でも、拍手を送るにはちょっと雑な推理ね。","ENG":"But it's way too flawed to be a good one.","TWN":"不過還不夠緊湊，不足以讓我為妳喝彩。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그래 봐야 정황증거일 뿐이잖아. 뭔가 물증 같은 건 없어?","JPN":"だって状況証拠にしかならないでしょ？　何か物証はないの？","ENG":"Everything you said is purely circumstantial. Don't you have any firm proof?","TWN":"妳說的都只是間接證據，就沒有什麼物證嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"뭐 그런 반응이 나올 거라고 생각했어요.","JPN":"そう言うと思いました。","ENG":"Well, I thought you might say that.","TWN":"我就知道妳會這麼說。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 선배를 추격하기 전에, 선배가 범인이 아닌 희생자일 가능성은 생각해 뒀거든요.","JPN":"残念ですが、先輩を追う前に、先輩が犯人じゃなくて犠牲者だという可能性を考えておいたんです。","ENG":"But before we went after Shiyoon, I thought about the possibility of his not being the perpetrator, but a victim.","TWN":"但我追蹤前輩之前，我早就想過前輩有可能就是受害者，而不是兇手。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그렇지 않아도 그때 다치지 않았냐면서 말을 걸어 주셨잖아요?","JPN":"ちょうどその時、私のこと心配をして声かけてくれましたよね？","ENG":"That was when you asked me if I was hurt.","TWN":"那時妳還問我是不是傷到哪裡了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그래. 무슨 생각에 잠겨 있나 궁금했는데 괜한 걱정이었나 보네.","JPN":"ええ、何か考え込んでるようだったから。でも余計な心配だったみたいね。","ENG":"Yes. I was worried because you looked troubled. Clearly, I worried for nothing.","TWN":"沒錯，我還很好奇妳在想些什麼。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아하하. 그래서 실은 선배를 쫓기 전에 베로니카 씨에게 도청기를 맡겼거든요.","JPN":"アハハ、実は先輩を追う前にベロニカさんに盗聴器を預けたんです。","ENG":"Ah hah hah. So, before we went after Shiyoon, I left a listening device with Veronica.","TWN":"啊哈哈，所以我追前輩之前，把竊聽器交給了貝洛妮卡。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"도청기를......?","JPN":"盗聴器を……？","ENG":"A listening device?","TWN":"竊聽器……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네. 그리고 방금 추격을 뿌리치는 과정에서 슬쩍 하는 데 성공했죠.","JPN":"はい。そしてさっきの追撃を振り切る途中で、それを回収したんです。","ENG":"Yes, and I managed to retrieve it before we ran away from her.","TWN":"是的，然後我剛剛躲避追擊的時候，偷偷拿回了竊聽器。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"어때요? 무슨 내용이 녹음되었을지 여기서 같이 들어 볼까요?","JPN":"どうです？　どんな内容が録音されてるか、一緒に聞いてみますか？","ENG":"Say, how about we play it and see what's been recorded?","TWN":"怎麼樣？要不要一起在這裡聽聽錄音？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"후훗. 제법이네, 알트 소대장님.","JPN":"ふふっ、やるじゃない。アルト小隊長さん？","ENG":"Hah hah. You're pretty good, ALT Squad Commander.","TWN":"哈哈，有妳的，阿爾特小隊隊長。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"사장님이 여러모로 칭찬하길래 설마 했는데, 기대 이상이야.","JPN":"社長が褒めてたから、まさかとは思ったけど。期待以上ね。","ENG":"There's a reason the Boss thinks so highly of you.","TWN":"老闆對妳讚不絕口，沒想到比我想的還要優秀。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 자신이 범인이라고 인정하는 건가요?","JPN":"自分が犯人だと認めるんですか？","ENG":"Are you admitting to your guilt?","TWN":"所以妳承認妳是兇手了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"왜? 못할 것 없지.","JPN":"どうして？　できないこともないでしょう？","ENG":"Sure, why not?","TWN":"怎麼？有什麼不能承認的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"맞아. 내가 바로 이 산장에 초대된 성야의 살인마야.","JPN":"そう。私がこの山荘に招待された聖夜の殺人鬼よ。","ENG":"Yes. I'm the Killer of the Holy Night invited over to this cabin.","TWN":"沒錯，我就是被邀請的耶誕的嫌疑犯。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"정말로...... 범인이었어?","JPN":"本当に……犯人だったの？","ENG":"Seriously? Are you the Killer?","TWN":"妳真的是……兇手？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"후우. 다행이네요.","JPN":"ふぅ、よかった。","ENG":"Whew, thank you!","TWN":"呼，真是萬幸。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"사실 이건 도청기가 아니거든요.","JPN":"実はこれ、盗聴器じゃなかったので。","ENG":"This is not actually a listening device.","TWN":"其實這不是竊聽器。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……どういうこと？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그냥 무전기에서 뗀 부품이에요. 아무리 저라도 항상 도청기를 들고 다닐 리 없잖아요.","JPN":"無線機から取ったただの部品です。いくら私でも盗聴器を常備してるわけないじゃないですか。","ENG":"It's just a part of a walkie-talkie. Even I don't carry listening devices with me all the time.","TWN":"這只是在對講機摘的零件。我怎麼可能每次都把竊聽器帶在身上。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"간단히 말하면, 뻥이란 뜻이죠.","JPN":"簡単に言うと、騙されたんですよ、アレックスさん。","ENG":"In other words, I bluffed.","TWN":"簡單來說，就是騙妳的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"혹시라도 끝까지 잡아떼면 어째야 할지 난감했는데 자백해 주셔서 너무나 고맙네요.","JPN":"もし最後までシラを切られたらどうしようかと思いましたが、\\n自白してくれてありがとうございます。","ENG":"I didn't know what to do if you refused to admit until the end. Thank you so much for not doing that.","TWN":"我還擔心如果妳一直不承認怎麼辦，這下好了，自己承認了，我應該感謝妳。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"다음부터는 다 끝난 판이라도 꼭 상대방의 패를 끝까지 확인하는 습관을 가지시는 게 좋겠어요.","JPN":"次からは最後まで相手の切り札を確認する癖をつけた方がいいですよ。","ENG":"But I suggest you check the other person's cards before showing yours, no matter how sure you are of your winning.","TWN":"下次即使認為妳已經完了，也最好還是確認一下對方的底牌是什麼吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"......후훗.","JPN":"……ふふっ。","ENG":"...Hah hah.","TWN":"……呼呼。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"이것 참, 이렇게 깔끔하게 얻어맞은 건 정말 오랜만이네.","JPN":"困るわね、こんな風にあっさり負けちゃったのは久々だわ。","ENG":"Wow, I haven't lost so soundly for a long time.","TWN":"好久沒這麼徹底地被算計了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"뒤통수치기랑 재뿌리기의 달인이라고 칭찬하던데 빈말이 아니었어.","JPN":"裏切りと破滅させるのが上手って褒めてたけど、嘘じゃなかったようね。","ENG":"You really are good at backstabbing and double-crossing.","TWN":"有人誇妳是背叛和妨礙的達人，看來說的沒錯。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......누가 그런 말을 했는지 대충 짐작은 가네요.","JPN":"……誰がそんなことを言ったのか、ある程度察しがつきますね。","ENG":"...I think I know who told you that.","TWN":"……我好像能猜到說那個話的人是誰。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨. 선배와 싸울 때 펼쳐 뒀던 전자기 펄스, 더 쓸 수 있나요?","JPN":"シルビアさん、先輩と戦う時に張った電磁パルス。もっと使えますか？","ENG":"Sylvia, do you have enough energy left to use an EMP, like you did to fight Shiyoon?","TWN":"希爾維亞，跟前輩打鬥時展開的電磁脈衝現在還能再用嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"날 뭘로 보는 거야. 아직 멀쩡해.","JPN":"あたしを誰だと思ってるの？　当たり前でしょ。","ENG":"Who do you think I am? Of course!","TWN":"當然了，還好好的呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"좋아요. 그럼 당장은 희생자들을 불러오진 못하겠죠.","JPN":"それなら今すぐ犠牲者を呼ぶことは難しいでしょう。","ENG":"Good, that'll keep her from calling the victims for a while.","TWN":"好，那她現在應該不能馬上召喚受害者了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"자, 순순히 항복하고 사람들을 원래대로 돌려 놓으세요!","JPN":"大人しく降参して、みんなを元に戻してください！","ENG":"Now, surrender and turn them back to normal!","TWN":"乖乖投降吧，然後把所有人都恢復成原樣。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};